const express = require('express')
const cors = require('cors')

const app = express()
app.use(express.json())
app.use(cors())

app.get('/', async (req, res) => {
  try {
    res.status(200)
    res.send({ data: 'test' })
  } catch (error) {
    res.status(500)
    res.end()
  }
})

// Mock authorization endpoint
// Accepts: { login: string, hash: string }
// Success login: admin / hash: any-non-empty (for demo)
app.post('/authorize', async (req, res) => {
  try {
    const { login, hash } = req.body || {}

    if (!login || !hash) {
      return res.status(400).send({ message: 'login and hash are required' })
    }

    // Simple demo validation. Replace with your own rules if needed.
    if (login === 'admin' && typeof hash === 'string' && hash.length > 0) {
      const now = new Date().toISOString()
      return res.status(200).send({
        isAuthorized: true,
        name: 'Admin User',
        login,
        token: 'mock-jwt-token',
        when: now,
        message: 'Authorized successfully',
      })
    }

    return res.status(401).send({ message: 'Invalid login or password' })
  } catch (error) {
    return res.status(500).send({ message: 'Internal Server Error' })
  }
})

